#include <linux/types.h>
#include <linux/bpf.h>

#include <bpf/bpf_helpers.h>
#include <bpf/bpf_tracing.h>



const __u32 pid_threshold = 0;

struct {
    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u64);
} counter SEC(".maps");

struct {
    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u32); /* target tgid */
} cfg SEC(".maps");

SEC("tracepoint/syscalls/sys_enter_openat")
int isa_upgrade_incompatible(struct trace_event_raw_sys_enter *ctx)
{
    __u32 key = 0;
    __u64 *val = bpf_map_lookup_elem(&counter, &key);
    __u32 *target_tgid = bpf_map_lookup_elem(&cfg, &key);
    __u32 pid = (__u32)(bpf_get_current_pid_tgid() >> 32);

    if (!val)
        return 0;

    if (target_tgid && *target_tgid && pid != *target_tgid)
        return 0;

    __u32 i = 0;
    /* Crutial block */
    while (i < 100){    // bounded loop
        i++;
        if (i % 2 == 0)
            pid += 1;
        else
            pid -= 1;
    }
    /* Crutial block end */
    if (pid > pid_threshold)
        (*val)++;

    return 0;
}

char LICENSE[] SEC("license") = "GPL";

repair_action.repair_method:
修改代码，在 loop_support.bpf.c 中存在循环的函数内，于循环语句前添加 `#pragma unroll` 指令，指示编译器在编译时将该循环完全展开为顺序执行的线性代码，从而彻底消除指令流中的回跳指令（back-edge），使 BPF 验证器无需证明循环边界即可接受程序。若循环体较大导致单函数指令数超过验证器上限（约 100 万条指令的实际限制，但单 BPF 程序通常建议不超过几千条），可同步减少循环迭代次数。示例：在 for 循环前添加 `#pragma unroll` 使其变为 `for (...) { #pragma unroll
  ...
}` 或直接在循环体上方单独写 `#pragma unroll`。
